using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O — use async throughout.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" via HasDiscriminator.
        // Without that opt-in, EF Core 9 would write "$type" and this query would find nothing.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync methods (ToList, SaveChanges, etc.) now throw on the Cosmos provider.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

